What does this program print on a 64-bit system where `int` is 4 bytes and a pointer is 8 bytes?

```cpp
#include <iostream>

void check(int* arr) {
    std::cout << sizeof(arr) << '\n';
}

int main() {
    int data[6]{};
    std::cout << sizeof(data) << '\n';
    check(data);
}
```

What does this program print?

```cpp
#include <iostream>

void show(const int* arr, int count) {
    for (int i = 0; i < count; ++i)
        std::cout << arr[i] << '\n';
}

int main() {
    int nums[3]{ 5, 10, 15 };
    show(nums, 3);
}
```

This program tries to print the number of elements but always prints 2 on a 64-bit system. What is the bug?

```cpp
#include <iostream>

void printCount(int arr[]) {
    std::cout << sizeof(arr) / sizeof(arr[0]) << '\n';
}

int main() {
    int data[5]{ 1, 2, 3, 4, 5 };
    printCount(data);
}
```
